static gboolean cloud_firestore_message_codec_write_value(FlStandardMessageCodec* codec, GByteArray* buffer, FlValue* value, GError** error) {
  if (fl_value_get_type(value) == FL_VALUE_TYPE_CUSTOM) {
    switch (fl_value_get_custom_type(value)) {
      case cloud_firestore_document_change_type_type_id:
        return cloud_firestore_message_codec_write_cloud_firestore_document_change_type(codec, buffer, reinterpret_cast<FlValue*>(const_cast<gpointer>(fl_value_get_custom_value(value))), error);
      case cloud_firestore_source_type_id:
        return cloud_firestore_message_codec_write_cloud_firestore_source(codec, buffer, reinterpret_cast<FlValue*>(const_cast<gpointer>(fl_value_get_custom_value(value))), error);
      case cloud_firestore_listen_source_type_id:
        return cloud_firestore_message_codec_write_cloud_firestore_listen_source(codec, buffer, reinterpret_cast<FlValue*>(const_cast<gpointer>(fl_value_get_custom_value(value))), error);
      case cloud_firestore_server_timestamp_behavior_type_id:
        return cloud_firestore_message_codec_write_cloud_firestore_server_timestamp_behavior(codec, buffer, reinterpret_cast<FlValue*>(const_cast<gpointer>(fl_value_get_custom_value(value))), error);
      case cloud_firestore_aggregate_source_type_id:
        return cloud_firestore_message_codec_write_cloud_firestore_aggregate_source(codec, buffer, reinterpret_cast<FlValue*>(const_cast<gpointer>(fl_value_get_custom_value(value))), error);
      case cloud_firestore_persistence_cache_index_manager_request_type_id:
        return cloud_firestore_message_codec_write_cloud_firestore_persistence_cache_index_manager_request(codec, buffer, reinterpret_cast<FlValue*>(const_cast<gpointer>(fl_value_get_custom_value(value))), error);
      case cloud_firestore_internal_transaction_result_type_id:
        return cloud_firestore_message_codec_write_cloud_firestore_internal_transaction_result(codec, buffer, reinterpret_cast<FlValue*>(const_cast<gpointer>(fl_value_get_custom_value(value))), error);
      case cloud_firestore_internal_transaction_type_type_id:
        return cloud_firestore_message_codec_write_cloud_firestore_internal_transaction_type(codec, buffer, reinterpret_cast<FlValue*>(const_cast<gpointer>(fl_value_get_custom_value(value))), error);
      case cloud_firestore_aggregate_type_type_id:
        return cloud_firestore_message_codec_write_cloud_firestore_aggregate_type(codec, buffer, reinterpret_cast<FlValue*>(const_cast<gpointer>(fl_value_get_custom_value(value))), error);
      case cloud_firestore_internal_firebase_settings_type_id:
        return cloud_firestore_message_codec_write_cloud_firestore_internal_firebase_settings(codec, buffer, CLOUD_FIRESTORE_INTERNAL_FIREBASE_SETTINGS(fl_value_get_custom_value_object(value)), error);
      case cloud_firestore_firestore_pigeon_firebase_app_type_id:
        return cloud_firestore_message_codec_write_cloud_firestore_firestore_pigeon_firebase_app(codec, buffer, CLOUD_FIRESTORE_FIRESTORE_PIGEON_FIREBASE_APP(fl_value_get_custom_value_object(value)), error);
      case cloud_firestore_internal_snapshot_metadata_type_id:
        return cloud_firestore_message_codec_write_cloud_firestore_internal_snapshot_metadata(codec, buffer, CLOUD_FIRESTORE_INTERNAL_SNAPSHOT_METADATA(fl_value_get_custom_value_object(value)), error);
      case cloud_firestore_internal_document_snapshot_type_id:
        return cloud_firestore_message_codec_write_cloud_firestore_internal_document_snapshot(codec, buffer, CLOUD_FIRESTORE_INTERNAL_DOCUMENT_SNAPSHOT(fl_value_get_custom_value_object(value)), error);
      case cloud_firestore_internal_document_change_type_id:
        return cloud_firestore_message_codec_write_cloud_firestore_internal_document_change(codec, buffer, CLOUD_FIRESTORE_INTERNAL_DOCUMENT_CHANGE(fl_value_get_custom_value_object(value)), error);
      case cloud_firestore_internal_query_snapshot_type_id:
        return cloud_firestore_message_codec_write_cloud_firestore_internal_query_snapshot(codec, buffer, CLOUD_FIRESTORE_INTERNAL_QUERY_SNAPSHOT(fl_value_get_custom_value_object(value)), error);
      case cloud_firestore_internal_pipeline_result_type_id:
        return cloud_firestore_message_codec_write_cloud_firestore_internal_pipeline_result(codec, buffer, CLOUD_FIRESTORE_INTERNAL_PIPELINE_RESULT(fl_value_get_custom_value_object(value)), error);
      case cloud_firestore_internal_pipeline_snapshot_type_id:
        return cloud_firestore_message_codec_write_cloud_firestore_internal_pipeline_snapshot(codec, buffer, CLOUD_FIRESTORE_INTERNAL_PIPELINE_SNAPSHOT(fl_value_get_custom_value_object(value)), error);
      case cloud_firestore_internal_get_options_type_id:
        return cloud_firestore_message_codec_write_cloud_firestore_internal_get_options(codec, buffer, CLOUD_FIRESTORE_INTERNAL_GET_OPTIONS(fl_value_get_custom_value_object(value)), error);
      case cloud_firestore_internal_document_option_type_id:
        return cloud_firestore_message_codec_write_cloud_firestore_internal_document_option(codec, buffer, CLOUD_FIRESTORE_INTERNAL_DOCUMENT_OPTION(fl_value_get_custom_value_object(value)), error);
      case cloud_firestore_internal_transaction_command_type_id:
        return cloud_firestore_message_codec_write_cloud_firestore_internal_transaction_command(codec, buffer, CLOUD_FIRESTORE_INTERNAL_TRANSACTION_COMMAND(fl_value_get_custom_value_object(value)), error);
      case cloud_firestore_document_reference_request_type_id:
        return cloud_firestore_message_codec_write_cloud_firestore_document_reference_request(codec, buffer, CLOUD_FIRESTORE_DOCUMENT_REFERENCE_REQUEST(fl_value_get_custom_value_object(value)), error);
      case cloud_firestore_internal_query_parameters_type_id:
        return cloud_firestore_message_codec_write_cloud_firestore_internal_query_parameters(codec, buffer, CLOUD_FIRESTORE_INTERNAL_QUERY_PARAMETERS(fl_value_get_custom_value_object(value)), error);
      case cloud_firestore_aggregate_query_type_id:
        return cloud_firestore_message_codec_write_cloud_firestore_aggregate_query(codec, buffer, CLOUD_FIRESTORE_AGGREGATE_QUERY(fl_value_get_custom_value_object(value)), error);
      case cloud_firestore_aggregate_query_response_type_id:
        return cloud_firestore_message_codec_write_cloud_firestore_aggregate_query_response(codec, buffer, CLOUD_FIRESTORE_AGGREGATE_QUERY_RESPONSE(fl_value_get_custom_value_object(value)), error);
    }
  }

  // Modified from the generated fallback (which chains to the parent class):
  // delegate unknown types to the Firestore codec, mirroring how the Windows
  // generated codec extends cloud_firestore_windows::FirestoreCodec.
  return firestore_codec_write_value(codec, buffer, value, error);
}

